import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"一份好的文件，能讓 Haiku 執行得像 Opus 一樣好？","description":"","frontmatter":{"title":"一份好的文件，能讓 Haiku 執行得像 Opus 一樣好？","date":"2026-04-29T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-29-agents-md-haiku-opus-taiwan.md","filePath":"research/ai-articles/scored/2026-04-29-agents-md-haiku-opus-taiwan.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/scored/2026-04-29-agents-md-haiku-opus-taiwan.md"};function d(i,t,n,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="一份好的文件-能讓-haiku-執行得像-opus-一樣好" tabindex="-1">一份好的文件，能讓 Haiku 執行得像 Opus 一樣好？ <a class="header-anchor" href="#一份好的文件-能讓-haiku-執行得像-opus-一樣好" aria-label="Permalink to &quot;一份好的文件，能讓 Haiku 執行得像 Opus 一樣好？&quot;">​</a></h1><p><strong>作者</strong>: 台灣社群（繁中評論與詮釋）<br><strong>來源</strong>: Facebook 分享（2026-04-29）<br><strong>原文參考</strong>: Augment Code 2026-04-22</p><h2 id="評分-5-維度" tabindex="-1">評分（5 維度） <a class="header-anchor" href="#評分-5-維度" aria-label="Permalink to &quot;評分（5 維度）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>得分</th><th>說明</th></tr></thead><tbody><tr><td>原創性</td><td>7/10</td><td>大量引用 Augment Code 原文，但加入在地見解與職業經驗詮釋</td></tr><tr><td>實用性</td><td>9/10</td><td>用中文白話解釋複雜概念，增進繁中社群理解；結尾組織意涵清晰</td></tr><tr><td>深度</td><td>7/10</td><td>傳播型而非研究型；著重「為什麼重要」而非「怎樣更深入」</td></tr><tr><td>清晰度</td><td>10/10</td><td>最強項。白話文表述、循序漸進、舉例貼近日常</td></tr><tr><td>相關性</td><td>9/10</td><td>強化 CLAUDE.md 「context engineering」和「三層載入」的設計思想</td></tr><tr><td><strong>平均</strong></td><td><strong>8.4/10</strong></td><td><strong>強烈推薦收錄</strong></td></tr></tbody></table><hr><h2 id="核心貢獻" tabindex="-1">核心貢獻 <a class="header-anchor" href="#核心貢獻" aria-label="Permalink to &quot;核心貢獻&quot;">​</a></h2><h3 id="_1-在地化詮釋-最有價值之處" tabindex="-1">1. 在地化詮釋（最有價值之處） <a class="header-anchor" href="#_1-在地化詮釋-最有價值之處" aria-label="Permalink to &quot;1. 在地化詮釋（最有價值之處）&quot;">​</a></h3><p><strong>原文</strong>「好文件能把 Haiku 升級到 Opus」 →<br><strong>本文詮釋</strong>：拆解為「模型選擇迷思」的破解</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>常見誤解：最強模型 = 最好結果</span></span>
<span class="line"><span>正確認識：中階模型 + 清晰流程 &gt; 強模型 + 模糊需求</span></span></code></pre></div><p>作者自身背景（多年 AI 開發經驗）讓這個論點有說服力，不只是理論。</p><h3 id="_2-分層教學" tabindex="-1">2. 分層教學 <a class="header-anchor" href="#_2-分層教學" aria-label="Permalink to &quot;2. 分層教學&quot;">​</a></h3><p>按讀者認知階段：</p><ol><li>開場：與讀者共識（「大家常問什麼模型」）</li><li>引入：Augment Code 研究為什麼重要</li><li>核心 7 點：逐點白話拆解</li><li>組織延伸：跳脫技術層，談企業能力</li></ol><h3 id="_3-組織洞見的提升" tabindex="-1">3. 組織洞見的提升 <a class="header-anchor" href="#_3-組織洞見的提升" aria-label="Permalink to &quot;3. 組織洞見的提升&quot;">​</a></h3><p>原文偏技術工程師視角；本文加上管理視角：</p><blockquote><p>AGENTS.md 是一種新的組織能力：把資深同仁腦裡的默契，轉成 AI 可理解、可執行的操作系統。</p></blockquote><p><strong>含義轉變</strong>：從「寫給 Agent 的文件」→ 「組織工作系統的新形式」</p><hr><h2 id="七點白話詮釋-對照原文" tabindex="-1">七點白話詮釋（對照原文） <a class="header-anchor" href="#七點白話詮釋-對照原文" aria-label="Permalink to &quot;七點白話詮釋（對照原文）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原文模式</th><th>本文詮釋</th><th>新增洞見</th></tr></thead><tbody><tr><td>Progressive Disclosure</td><td>不要一次塞太多</td><td>類比「新進員工 onboarding」</td></tr><tr><td>Procedural Workflows</td><td>把任務拆成清楚步驟</td><td>Agent 需要「一條清楚的路」</td></tr><tr><td>Decision Tables</td><td>遇到選擇題先寫判斷標準</td><td>把選擇「提前處理」而非「臨場猜測」</td></tr><tr><td>Production Examples</td><td>給 3-10 行真實程式碼</td><td>「學寫作看 2 篇好範例勝過 10 篇雜亂」</td></tr><tr><td>Domain Rules</td><td>規則要具體，不漂亮話</td><td>「資料品質」vs 「payment_logs 必須同步」</td></tr><tr><td>Pair + Solutions</td><td>不只禁止，要給替代方案</td><td>Agent 不是不認真，是被提供替代資訊</td></tr><tr><td>Modular Docs</td><td>模組化參考</td><td>避免「全部丟進去期待自然變強」的陷阱</td></tr></tbody></table><hr><h2 id="壞文件的三大危害-新增細節" tabindex="-1">壞文件的三大危害（新增細節） <a class="header-anchor" href="#壞文件的三大危害-新增細節" aria-label="Permalink to &quot;壞文件的三大危害（新增細節）&quot;">​</a></h2><ol><li><strong>過度探索</strong> — 文件太大拉走 Agent 注意力</li><li><strong>語氣模糊</strong> — 「優先」vs「必須」Agent 理解不穩定</li><li><strong>過時文件最危險</strong> — Agent 會很認真實作過期的架構決策</li></ol><p><strong>特別提醒</strong>：「壞文件不中性，它主動傷害結果」</p><hr><h2 id="workspace-應用亮點" tabindex="-1">Workspace 應用亮點 <a class="header-anchor" href="#workspace-應用亮點" aria-label="Permalink to &quot;Workspace 應用亮點&quot;">​</a></h2><h3 id="跨出-coding-agent-的推廣" tabindex="-1">跨出 Coding Agent 的推廣 <a class="header-anchor" href="#跨出-coding-agent-的推廣" aria-label="Permalink to &quot;跨出 Coding Agent 的推廣&quot;">​</a></h3><p>本文特別指出：客服、營運、財務、法務 Agent 都需要等效文件。</p><p><strong>含義</strong>：AGENTS.md 概念不是 niche，而是 AI Agent 時代的通用管理工具。</p><h3 id="企業管理視角" tabindex="-1">企業管理視角 <a class="header-anchor" href="#企業管理視角" aria-label="Permalink to &quot;企業管理視角&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>過去：管理人</span></span>
<span class="line"><span>現在：管理「人與 Agent 共同工作的系統」</span></span></code></pre></div><p>這是對 CLAUDE.md 整個哲學的高度總結。</p><hr><h2 id="引申思考-本文獨有" tabindex="-1">引申思考（本文獨有） <a class="header-anchor" href="#引申思考-本文獨有" aria-label="Permalink to &quot;引申思考（本文獨有）&quot;">​</a></h2><h3 id="「寫到-agent-看得懂-真的想清楚」" tabindex="-1">「寫到 Agent 看得懂 = 真的想清楚」 <a class="header-anchor" href="#「寫到-agent-看得懂-真的想清楚」" aria-label="Permalink to &quot;「寫到 Agent 看得懂 = 真的想清楚」&quot;">​</a></h3><blockquote><p>當你能把一件事寫到 AI Agent 看得懂、做得到、驗證得出來，通常也代表你真的把這件事想清楚了。</p></blockquote><p>這是一個強有力的清晰度測試：<strong>能給 Agent 的指令 = 真正理解的標誌</strong></p><h3 id="模型升級-vs-環境升級" tabindex="-1">模型升級 vs 環境升級 <a class="header-anchor" href="#模型升級-vs-環境升級" aria-label="Permalink to &quot;模型升級 vs 環境升級&quot;">​</a></h3><p>結尾的反思很關鍵：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不要急著只升級模型，也要升級 Agent 工作的環境。</span></span></code></pre></div><p>對應 workspace 的實踐：CLAUDE.md 設計逐年迭代，比每年換新模型的效果更持久。</p><hr><h2 id="評論" tabindex="-1">評論 <a class="header-anchor" href="#評論" aria-label="Permalink to &quot;評論&quot;">​</a></h2><h3 id="優點" tabindex="-1">優點 <a class="header-anchor" href="#優點" aria-label="Permalink to &quot;優點&quot;">​</a></h3><ol><li><strong>清晰傳播</strong> — 用中文社群能理解的語言重述複雜研究</li><li><strong>組織化視角</strong> — 突破技術視角，提升到「組織能力」層級</li><li><strong>實踐感</strong> — 作者背景加入個人經驗，不只引述</li><li><strong>結構清晰</strong> — 開場引入、核心 7 點、反面失敗、應用推廣層層遞進</li></ol><h3 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h3><ol><li><strong>深度取捨</strong> — 為了傳播易懂，減少了原文的數據細節（沒有列出具體 +25% / -30%）</li><li><strong>未深化研究</strong> — 對「為什麼」的解釋停留在直觀（原文稍好）</li><li><strong>未加驗證</strong> — 沒有對台灣專案的實踐案例驗證</li></ol><h3 id="與原文的互補性" tabindex="-1">與原文的互補性 <a class="header-anchor" href="#與原文的互補性" aria-label="Permalink to &quot;與原文的互補性&quot;">​</a></h3><ul><li><strong>英文原文</strong>：數據驅動、細節完整、工程師視角</li><li><strong>本文</strong>：傳播優先、組織視角、中文社群易入門</li></ul><p><strong>建議讀法</strong>：先讀本文建立全景，再讀英文原文深化細節。</p><hr><h2 id="對-workspace-的啟發" tabindex="-1">對 Workspace 的啟發 <a class="header-anchor" href="#對-workspace-的啟發" aria-label="Permalink to &quot;對 Workspace 的啟發&quot;">​</a></h2><h3 id="_1-claude-md-設計的驗證" tabindex="-1">1. CLAUDE.md 設計的驗證 <a class="header-anchor" href="#_1-claude-md-設計的驗證" aria-label="Permalink to &quot;1. CLAUDE.md 設計的驗證&quot;">​</a></h3><p>本文提及的七點模式，workspace 已實踐 6/7：</p><ul><li>✅ Progressive Disclosure（常駐層 + 按需層）</li><li>✅ Procedural Workflows（/deep-review 檢查表）</li><li>✅ Decision Tables（.claude/rules/ 決策樹）</li><li>✅ Production Examples（playbooks/）</li><li>✅ Domain Rules（各 rules 檔的具體約定）</li><li>✅ Pair + Solutions（core.md 的外科刀修改正確做法）</li><li>⚠️ Modular Docs（仍在優化中，避免三層深度參考）</li></ul><h3 id="_2-三層載入哲學的確認" tabindex="-1">2. 三層載入哲學的確認 <a class="header-anchor" href="#_2-三層載入哲學的確認" aria-label="Permalink to &quot;2. 三層載入哲學的確認&quot;">​</a></h3><p>CLAUDE.md 的「常駐 + 按需 + 手動」正是 <strong>Progressive Disclosure</strong> 的實踐。</p><p>本文佐證了這個設計不是過度工程，而是應對 context 爆炸的必要手段。</p><h3 id="_3-跨功能應用機會" tabindex="-1">3. 跨功能應用機會 <a class="header-anchor" href="#_3-跨功能應用機會" aria-label="Permalink to &quot;3. 跨功能應用機會&quot;">​</a></h3><p>workspace 目前焦點在 coding agent（CLAUDE.md）。<br> 本文啟發：相同原則可推廣到 Operations / Data / Infrastructure agent。</p><hr><h2 id="標籤" tabindex="-1">標籤 <a class="header-anchor" href="#標籤" aria-label="Permalink to &quot;標籤&quot;">​</a></h2><p><code>agents-md</code> <code>context-engineering</code> <code>organization-capability</code> <code>ai-agent-design</code> <code>claire-md-design</code> <code>台灣社群</code> <code>傳播型研究</code></p>`,63)])])}const u=a(s,[["render",d]]);export{g as __pageData,u as default};
